import { useState } from 'react';
import React from 'react';
import   './Corepin.css';

import SProduct1 from '../../Assets/industry.webp';


const Corepins = () => {
  
    const [r1, setR1] = useState(true);
    const [r2, setR2] = useState(false);
    const [r3, setR3] = useState(false);
    const [r4, setR4] = useState(false);
    const [r5, setR5] = useState(false);
    const [r6, setR6] = useState(false);


    const clkHnd1 = () => {
        setR1(true);
        setR2(false);
        setR3(false);
        setR4(false);
        setR5(false);
    };

    const clkHnd2 = () => {
        setR1(false);
        setR2(true);
        setR3(false);
        setR4(false);
        setR5(false);
    };

    const clkHnd3 = () => {
        setR1(false);
        setR2(false);
        setR3(true);
        setR4(false);
        setR5(false);
    };

    const clkHnd4 = () => {
        setR1(false);
        setR2(false);
        setR3(false);
        setR4(true);
        setR5(false);
    };

    const clkHnd5 = () => {
        setR1(false);
        setR2(false);
        setR3(false);
        setR4(false);
        setR5(true);
    };
  return (
       <section>
            
             <div className='AccHold'>
            <div className='left'>
                <button className={r1 ? 'AccBtn1 AccBtn11' : 'AccBtn'} onClick={clkHnd1}>Indusrial Core Plus </button>
                <button className={r2 ? 'AccBtn1' : 'AccBtn'} onClick={clkHnd2}>H13 Core Pin</button>
                <button className={r3 ? 'AccBtn1' : 'AccBtn'} onClick={clkHnd3}>Orvar Supreme Core Pin</button>
                <button className={r4 ? 'AccBtn1' : 'AccBtn'} onClick={clkHnd4}>Core Pine</button>
                <button className={r5 ? 'AccBtn1' : 'AccBtn'} onClick={clkHnd5}>Core Pine HDS H13</button>
                <button className={r6 ? 'AccBtn1' : 'AccBtn'} onClick={clkHnd6}>Diamond Locating Pin</button>
            </div>
            <div className='right'>

                {r1 && <div className='right1'>
                    <div className='accContainIn'>
                        
                    <div className= 'SProduct1'> 
                          
                          <img src={SProduct1} className='Product1'></img>

                    
                          <table>
